function login(){let u=document.getElementById("lu").value,p=document.getElementById("lp").value;console.log(q("login","POST",{username:u,clear_password:p}))}function register(){let u=document.getElementById("ru").value,p=document.getElementById("rp").value,p2=document.getElementById("rpc").value;console.log(q("register","POST",{username:u,clear_password:p,clear_password_2:p2}))}async function q(url,method,data){try{const response=await fetch(url,{method:method,headers:{Accept:"application/json","Content-Type":"application/json"},body:JSON.stringify(data)}),res=response.json;200===res.status&&console.log("Q OK")}catch(err){console.log("Q "+err)}}window.onload=function(){var token=localStorage.getItem("token")},document.addEventListener("DOMContentLoaded",()=>{function openModal($el){$el.classList.add("is-active")}function closeModal($el){$el.classList.remove("is-active")}function closeAllModals(){(document.querySelectorAll(".modal")||[]).forEach($modal=>{closeModal($modal)})}(document.querySelectorAll(".js-modal-trigger")||[]).forEach($trigger=>{const modal=$trigger.dataset.target,$target=document.getElementById(modal);$trigger.addEventListener("click",()=>{openModal($target)})}),(document.querySelectorAll(".modal-background, .modal-close, .modal-card-head .delete, .modal-card-foot .button")||[]).forEach($close=>{const $target=$close.closest(".modal");$close.addEventListener("click",()=>{closeModal($target)})}),document.addEventListener("keydown",event=>{const e=event||window.event;"Escape"==e.key&&closeAllModals()})});